package analytics

import (
	"context"

	"socialpredict/internal/domain/boundary"
	positionsmath "socialpredict/internal/domain/math/positions"
)

// DebtRepository exposes only the user data needed for debt calculations.
type DebtRepository interface {
	ListUsers(ctx context.Context) ([]UserAccount, error)
}

// VolumeRepository exposes the market and bet data needed for volume calculations.
type VolumeRepository interface {
	ListMarkets(ctx context.Context) ([]MarketRecord, error)
	ListBetsForMarket(ctx context.Context, marketID uint) ([]boundary.Bet, error)
}

// FeeRepository exposes the ordered bet data needed for participation fee calculations.
type FeeRepository interface {
	ListBetsOrdered(ctx context.Context) ([]boundary.Bet, error)
}

// LeaderboardRepository provides the data required to compute leaderboards.
type LeaderboardRepository interface {
	DebtRepository
	VolumeRepository
}

// FinancialsRepository provides the data required for per-user financial snapshots.
type FinancialsRepository interface {
	UserMarketPositions(ctx context.Context, username string) ([]positionsmath.MarketPosition, error)
}

// StatsRepository exposes aggregate account data required by stats reporting.
type StatsRepository interface {
	CountUsersByType(ctx context.Context, userType string) (int64, error)
}

// Config captures the accounting-relevant policy slice required by analytics.
// It is a process-start snapshot; historically exact fee or cost reporting across
// future economics rollouts still requires durable per-market or per-bet policy capture.
type Config struct {
	MaximumDebtAllowed int64
	CreateMarketCost   int64
	InitialBetFee      int64
}

// DebtCalculator calculates debt-related metrics.
type DebtCalculator interface {
	Calculate(ctx context.Context, repo DebtRepository, config Config) (*DebtStats, error)
}

// VolumeCalculator calculates market volume metrics.
type VolumeCalculator interface {
	Calculate(ctx context.Context, repo VolumeRepository, config Config) (*MarketVolumeStats, error)
}

// FeeCalculator calculates betting fee metrics.
type FeeCalculator interface {
	CalculateParticipationFees(ctx context.Context, repo FeeRepository, config Config) (int64, error)
}

// MetricsAssembler combines calculator outputs into the final DTO.
type MetricsAssembler interface {
	Assemble(debt *DebtStats, volume *MarketVolumeStats, participationFees int64) *SystemMetrics
}

// MarketPositionCalculator calculates market positions for analytics consumers.
type MarketPositionCalculator interface {
	Calculate(snapshot positionsmath.MarketSnapshot, bets []boundary.Bet) ([]positionsmath.MarketPosition, error)
}

// Repository exposes the data access required by the analytics domain service.
type Repository interface {
	LeaderboardRepository
	FeeRepository
	FinancialsRepository
	StatsRepository
}

// Service implements analytics calculations.
type Service struct {
	repo             Repository
	debtRepo         DebtRepository
	volumeRepo       VolumeRepository
	feeRepo          FeeRepository
	leaderboardRepo  LeaderboardRepository
	financialsRepo   FinancialsRepository
	statsRepo        StatsRepository
	config           Config
	debtCalculator   DebtCalculator
	volumeCalculator VolumeCalculator
	feeCalculator    FeeCalculator
	metricsAssembler MetricsAssembler
	positions        MarketPositionCalculator
}

// ServiceOption allows customizing analytics strategies.
type ServiceOption func(*Service)

func defaultDebtCalculator() DebtCalculator {
	return DefaultDebtCalculator{}
}

func defaultVolumeCalculator() VolumeCalculator {
	return DefaultVolumeCalculator{}
}

func defaultFeeCalculator() FeeCalculator {
	return DefaultFeeCalculator{}
}

func defaultMetricsAssembler() MetricsAssembler {
	return DefaultMetricsAssembler{}
}

func defaultPositionCalculator() MarketPositionCalculator {
	return defaultMarketPositionCalculator{}
}

func debtCalculatorOrDefault(calculator DebtCalculator) DebtCalculator {
	if calculator == nil {
		return defaultDebtCalculator()
	}
	return calculator
}

func volumeCalculatorOrDefault(calculator VolumeCalculator) VolumeCalculator {
	if calculator == nil {
		return defaultVolumeCalculator()
	}
	return calculator
}

func feeCalculatorOrDefault(calculator FeeCalculator) FeeCalculator {
	if calculator == nil {
		return defaultFeeCalculator()
	}
	return calculator
}

func metricsAssemblerOrDefault(assembler MetricsAssembler) MetricsAssembler {
	if assembler == nil {
		return defaultMetricsAssembler()
	}
	return assembler
}

func positionCalculatorOrDefaultStrategy(calculator MarketPositionCalculator) MarketPositionCalculator {
	if calculator == nil {
		return defaultPositionCalculator()
	}
	return calculator
}

func (s *Service) setRepository(repo Repository) {
	if s == nil {
		return
	}
	s.repo = repo
	s.debtRepo = repo
	s.volumeRepo = repo
	s.feeRepo = repo
	s.leaderboardRepo = repo
	s.financialsRepo = repo
	s.statsRepo = repo
}

// WithDebtCalculator overrides the default debt calculator.
func WithDebtCalculator(c DebtCalculator) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.debtCalculator = debtCalculatorOrDefault(c)
		}
	}
}

// WithVolumeCalculator overrides the default volume calculator.
func WithVolumeCalculator(c VolumeCalculator) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.volumeCalculator = volumeCalculatorOrDefault(c)
		}
	}
}

// WithFeeCalculator overrides the default fee calculator.
func WithFeeCalculator(c FeeCalculator) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.feeCalculator = feeCalculatorOrDefault(c)
		}
	}
}

// WithMetricsAssembler overrides the default metrics assembler.
func WithMetricsAssembler(a MetricsAssembler) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.metricsAssembler = metricsAssemblerOrDefault(a)
		}
	}
}

// WithPositionCalculator overrides the default position calculator.
func WithPositionCalculator(c MarketPositionCalculator) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.positions = positionCalculatorOrDefaultStrategy(c)
		}
	}
}

// NewService constructs an analytics service with optional strategy overrides.
func NewService(repo Repository, config Config, opts ...ServiceOption) *Service {
	service := &Service{
		config: config,
	}
	service.setRepository(repo)

	for _, opt := range opts {
		opt(service)
	}

	service.ensureStrategyDefaults()

	return service
}

func (s *Service) ensureStrategyDefaults() {
	if s == nil {
		return
	}
	s.debtCalculator = debtCalculatorOrDefault(s.debtCalculator)
	s.volumeCalculator = volumeCalculatorOrDefault(s.volumeCalculator)
	s.feeCalculator = feeCalculatorOrDefault(s.feeCalculator)
	s.metricsAssembler = metricsAssemblerOrDefault(s.metricsAssembler)

package homepage

import (
	"bytes"
	"errors"
	"socialpredict/models"

	"github.com/microcosm-cc/bluemonday"
	"github.com/yuin/goldmark"
	"github.com/yuin/goldmark/renderer/html"
)

type Renderer interface {
	MarkdownToHTML(md string) (string, error)
	SanitizeHTML(html string) string
}

type DefaultRenderer struct {
	md goldmark.Markdown
	pm *bluemonday.Policy
}

func NewDefaultRenderer() *DefaultRenderer {
	// Create a permissive policy for rich HTML content with Tailwind classes
	policy := bluemonday.NewPolicy()

	// Allow all common HTML structural elements
	policy.AllowElements(
		"div", "section", "p", "span",
		"h1", "h2", "h3", "h4", "h5", "h6",
		"ul", "ol", "li",
		"a", "img",
		"strong", "em", "b", "i",
		"br", "hr",
	)

	// Allow class and id attributes on all elements (for Tailwind CSS)
	policy.AllowAttrs("class", "id").Globally()

	// Allow accessibility attributes globally
	policy.AllowAttrs(
		"aria-labelledby", "aria-describedby", "aria-label", "aria-hidden",
		"role", "tabindex", "aria-expanded", "aria-controls",
	).Globally()

	// Allow specific attributes for links
	policy.AllowAttrs("href", "target", "rel", "title").OnElements("a")

	// Allow specific attributes for images (including performance attributes)
	policy.AllowAttrs(
		"src", "alt", "width", "height", "title",
		"loading", "decoding", // Performance attributes
	).OnElements("img")

	// Allow URL schemes for links and images (including relative paths)
	policy.AllowURLSchemes("http", "https", "mailto")
	policy.AllowRelativeURLs(true) // Allow relative URLs like "/HomePageLogo.png"

	return &DefaultRenderer{
		md: goldmark.New(
			goldmark.WithRendererOptions(
				html.WithUnsafe(),
			),
		),
		pm: policy,
	}
}

func (r *DefaultRenderer) MarkdownToHTML(md string) (string, error) {
	var w = new(bytes.Buffer)
	if err := r.md.Convert([]byte(md), w); err != nil {
		return "", err
	}
	return w.String(), nil
}

func (r *DefaultRenderer) SanitizeHTML(html string) string {
	return r.pm.Sanitize(html)
}

// Use higher-order injection for renderer & repository for testability.
type Service struct {
	repo     Repository
	renderer Renderer
}

func NewService(repo Repository, renderer Renderer) *Service {
	return &Service{repo: repo, renderer: renderer}
}

type UpdateInput struct {
	Title     string
	Format    string // "markdown" or "html"
	Markdown  string
	HTML      string
	UpdatedBy string
	Version   uint
}

func (s *Service) GetHome() (*models.HomepageContent, error) {
	return s.repo.GetBySlug("home")
}

func (s *Service) UpdateHome(in UpdateInput) (*models.HomepageContent, error) {
	item, err := s.repo.GetBySlug("home")
	if err != nil {
		return nil, err
	}
	// optimistic lock check (optional; keep consistent with your style)
	if in.Version != 0 && in.Version != item.Version {
		return nil, errors.New("version mismatch")
	}

	item.Title = in.Title
	item.Format = in.Format
	item.UpdatedBy = in.UpdatedBy
	item.Version = item.Version + 1

	switch in.Format {
	case "markdown":
		item.Markdown = in.Markdown
		rendered, err := s.renderer.MarkdownToHTML(in.Markdown)
		if err != nil {
			return nil, err
		}
		item.HTML = s.renderer.SanitizeHTML(rendered)
	case "html":
		item.HTML = s.renderer.SanitizeHTML(in.HTML)
		item.Markdown = "" // optional: clear or keep last md
	default:
		return nil, errors.New("unsupported format")
	}

	if err := s.repo.Save(item); err != nil {
		return nil, err
	}
	return item, nil
}

	s.positions = positionCalculatorOrDefaultStrategy(s.positions)
}

var (
	_ DebtCalculator           = defaultDebtCalculator()
	_ VolumeCalculator         = defaultVolumeCalculator()
	_ FeeCalculator            = defaultFeeCalculator()
	_ MetricsAssembler         = defaultMetricsAssembler()
	_ MarketPositionCalculator = defaultPositionCalculator()
)

package analytics

import (
	"context"
	"sort"
	"time"

	"socialpredict/internal/domain/boundary"
	positionsmath "socialpredict/internal/domain/math/positions"
)

// GlobalUserProfitability summarises a user's profitability across all markets.
type GlobalUserProfitability struct {
	Username          string    `json:"username"`
	TotalProfit       int64     `json:"totalProfit"`
	TotalCurrentValue int64     `json:"totalCurrentValue"`
	TotalSpent        int64     `json:"totalSpent"`
	ActiveMarkets     int       `json:"activeMarkets"`
	ResolvedMarkets   int       `json:"resolvedMarkets"`
	EarliestBet       time.Time `json:"earliestBet"`
	Rank              int       `json:"rank"`
}

// GlobalLeaderboardSnapshot is the analytics-owned result seam for the global
// leaderboard read. It keeps future caching behind the analytics boundary while
// preserving the existing HTTP response contract.
type GlobalLeaderboardSnapshot struct {
	Entries []GlobalUserProfitability
}

// Result returns the response-ready leaderboard entries.
func (s *GlobalLeaderboardSnapshot) Result() []GlobalUserProfitability {
	if s == nil || s.Entries == nil {
		return []GlobalUserProfitability{}
	}
	return s.Entries
}

// ComputeGlobalLeaderboardSnapshot ranks users by profitability across all markets.
func (s *Service) ComputeGlobalLeaderboardSnapshot(ctx context.Context) (*GlobalLeaderboardSnapshot, error) {
	users, err := s.repo.ListUsers(ctx)
	if err != nil {
		return nil, err
	}
	if len(users) == 0 {
		return newGlobalLeaderboardSnapshot(nil), nil
	}

	markets, err := s.repo.ListMarkets(ctx)
	if err != nil {
		return nil, err
	}
	if len(markets) == 0 {
		return newGlobalLeaderboardSnapshot(nil), nil
	}

	marketData, err := s.loadLeaderboardMarketData(ctx, markets)
	if err != nil {
		return nil, err
	}
	if len(marketData) == 0 {
		return newGlobalLeaderboardSnapshot(nil), nil
	}

	aggregates := aggregateLeaderboardUserStats(marketData)
	if len(aggregates) == 0 {
		return newGlobalLeaderboardSnapshot(nil), nil
	}

	earliestBets := findEarliestBetsPerUser(marketData, aggregates)
	leaderboard := assembleLeaderboardEntries(aggregates, earliestBets)
	return newGlobalLeaderboardSnapshot(rankLeaderboardEntries(leaderboard)), nil
}

// ComputeGlobalLeaderboard returns the legacy leaderboard slice for callers that
// do not need the snapshot seam.
func (s *Service) ComputeGlobalLeaderboard(ctx context.Context) ([]GlobalUserProfitability, error) {
	snapshot, err := s.ComputeGlobalLeaderboardSnapshot(ctx)
	if err != nil {
		return nil, err
	}
	return snapshot.Result(), nil
}

func newGlobalLeaderboardSnapshot(entries []GlobalUserProfitability) *GlobalLeaderboardSnapshot {
	if entries == nil {
		entries = []GlobalUserProfitability{}
	}
	return &GlobalLeaderboardSnapshot{Entries: entries}
}

type leaderboardMarketData struct {
	snapshot  positionsmath.MarketSnapshot
	positions []positionsmath.MarketPosition
	bets      []boundary.Bet
}

type leaderboardAggregate struct {
	totalProfit       int64
	totalCurrentValue int64
	totalSpent        int64
	activeMarkets     int
	resolvedMarkets   int
}

func (s *Service) loadLeaderboardMarketData(ctx context.Context, markets []MarketRecord) ([]leaderboardMarketData, error) {
	data := make([]leaderboardMarketData, 0, len(markets))

	for _, market := range markets {
		bets, err := s.repo.ListBetsForMarket(ctx, uint(market.ID))
		if err != nil {
			return nil, err
		}

		snapshot := market.Snapshot()

		if s.positions == nil {
			s.ensureStrategyDefaults()
		}

		marketPositions, err := s.positions.Calculate(snapshot, bets)
		if err != nil {
			return nil, err
		}

		data = append(data, leaderboardMarketData{
			snapshot:  snapshot,
			positions: marketPositions,
			bets:      bets,
		})
	}

	return data, nil
}

func aggregateLeaderboardUserStats(markets []leaderboardMarketData) map[string]*leaderboardAggregate {
	aggregates := make(map[string]*leaderboardAggregate)

	for _, market := range markets {
		for _, pos := range market.positions {
			agg := aggregates[pos.Username]
			if agg == nil {
				agg = &leaderboardAggregate{}
				aggregates[pos.Username] = agg
			}

			profit := pos.Value - pos.TotalSpent
			agg.totalProfit += profit
			agg.totalCurrentValue += pos.Value
			agg.totalSpent += pos.TotalSpent
			if pos.IsResolved {
				agg.resolvedMarkets++
			} else {
				agg.activeMarkets++
			}
		}
	}

	return aggregates
}

func findEarliestBetsPerUser(markets []leaderboardMarketData, aggregates map[string]*leaderboardAggregate) map[string]time.Time {
	earliest := make(map[string]time.Time)

	for _, market := range markets {
		for _, bet := range market.bets {
			if aggregates[bet.Username] == nil {
				continue
			}
			if ts, ok := earliest[bet.Username]; !ok || bet.PlacedAt.Before(ts) {
				earliest[bet.Username] = bet.PlacedAt
			}
		}
	}

	return earliest
}

func assembleLeaderboardEntries(aggregates map[string]*leaderboardAggregate, earliest map[string]time.Time) []GlobalUserProfitability {
	leaderboard := make([]GlobalUserProfitability, 0, len(aggregates))

	for username, agg := range aggregates {
		firstBet, ok := earliest[username]
		if !ok {
			continue
		}
		leaderboard = append(leaderboard, GlobalUserProfitability{
			Username:          username,
			TotalProfit:       agg.totalProfit,
			TotalCurrentValue: agg.totalCurrentValue,
			TotalSpent:        agg.totalSpent,
			ActiveMarkets:     agg.activeMarkets,
			ResolvedMarkets:   agg.resolvedMarkets,
			EarliestBet:       firstBet,
		})
	}

	return leaderboard
}

func rankLeaderboardEntries(entries []GlobalUserProfitability) []GlobalUserProfitability {
	sort.Slice(entries, func(i, j int) bool {
		if entries[i].TotalProfit == entries[j].TotalProfit {
			return entries[i].EarliestBet.Before(entries[j].EarliestBet)
		}
		return entries[i].TotalProfit > entries[j].TotalProfit
	})

	for i := range entries {
		entries[i].Rank = i + 1
	}

	return entries
}

package metricshandlers

import (
	"net/http"

	"socialpredict/handlers"
)

// GetGlobalLeaderboardHandler returns an application reporting handler for the global leaderboard.
func GetGlobalLeaderboardHandler(svc GlobalLeaderboardService) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		snapshot, err := svc.ComputeGlobalLeaderboardSnapshot(r.Context())
		if err != nil {
			_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
			return
		}

		if err := handlers.WriteResult(w, http.StatusOK, snapshot.Result()); err != nil {
			_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
		}
	}
}

package http

import (
	"context"
	"encoding/json"
	"net/http"
	"socialpredict/handlers"
	"socialpredict/handlers/authhttp"
	"socialpredict/handlers/cms/homepage"
	authsvc "socialpredict/internal/service/auth"
)

type Handler struct {
	svc  *homepage.Service
	auth authsvc.Authenticator
}

func NewHandler(svc *homepage.Service, auth authsvc.Authenticator) *Handler {
	return &Handler{svc: svc, auth: auth}
}

func (h *Handler) PublicGet(w http.ResponseWriter, r *http.Request) {
	item, err := h.svc.GetHome()
	if err != nil {
		_ = handlers.WriteFailure(w, http.StatusNotFound, handlers.ReasonNotFound)
		return
	}

	_ = handlers.WriteResult(w, http.StatusOK, map[string]interface{}{
		"title":     item.Title,
		"format":    item.Format,
		"html":      item.HTML,
		"markdown":  item.Markdown, // optional to expose
		"version":   item.Version,
		"updatedAt": item.UpdatedAt,
	})
}

type updateReq struct {
	Title    string `json:"title"`
	Format   string `json:"format"`   // "markdown" | "html"
	Markdown string `json:"markdown"` // when format=markdown
	HTML     string `json:"html"`     // when format=html
	Version  uint   `json:"version"`
}

func (h *Handler) AdminUpdate(w http.ResponseWriter, r *http.Request) {
	// Validate admin access
	if h.auth == nil {
		_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
		return
	}
	admin, authErr := h.auth.RequireAdmin(r)
	if authErr != nil {
		_ = authhttp.WriteFailure(w, authErr)
		return
	}

	var in updateReq
	if err := json.NewDecoder(r.Body).Decode(&in); err != nil {
		_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonInvalidRequest)
		return
	}

	item, err := h.svc.UpdateHome(homepage.UpdateInput{
		Title:     in.Title,
		Format:    in.Format,
		Markdown:  in.Markdown,
		HTML:      in.HTML,
		Version:   in.Version,
		UpdatedBy: admin.Username,
	})
	if err != nil {
		_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonValidationFailed)
		return
	}

	_ = handlers.WriteResult(w, http.StatusOK, map[string]interface{}{
		"title":     item.Title,
		"format":    item.Format,
		"html":      item.HTML,
		"markdown":  item.Markdown,
		"version":   item.Version,
		"updatedAt": item.UpdatedAt,
	})
}

// RequireAdmin middleware wrapper that can be used in routes when an authenticator is available.
func RequireAdmin(auth authsvc.Authenticator, next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if auth == nil {
			_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
			return
		}
		if _, authErr := auth.RequireAdmin(r); authErr != nil {
			_ = authhttp.WriteFailure(w, authErr)
			return
		}
		next.ServeHTTP(w, r)
	}
}

// UsernameFromContext extracts username from request context (helper function)
func UsernameFromContext(ctx context.Context) string {
	// This is a placeholder - in practice you might store username in context
	// during authentication middleware
	return "admin" // fallback for now
}

